76	describe("Auth - Protected Routes", () => {
77	  let token: string;
78	
79	  beforeAll(async () => {
80	    // Register and get a token
81	    const res = await request(app).post("/auth/register").send({
82	      username: "authuser",
83	      email: "authuser@example.com",
84	      password: "authpass",
